queries.sparql:
PREFIX : <http://ambrosia.example.org/filmmaking#>
PREFIX p: <http://ambrosia.example.org/filmmaking/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?o0 WHERE {
  {
    ?stunts a :Stunts .
    ?stunts p:Coordinator ?coordinator .
    ?stunts p:Experience ?experience_f .
    FILTER(STR(?experience_f) = "10 years")
    BIND(?coordinator AS ?o0)
  }
  UNION
  {
    ?fightscenes a :FightScenes .
    ?fightscenes p:Choreographer ?choreographer .
    ?fightscenes p:Experience ?experience_f .
    FILTER(STR(?experience_f) = "10 years")
    BIND(?choreographer AS ?o0)
  }
}

